import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AuthService } from '../../../core/services/auth.service';
import { MessageService } from '../../../shared/services/message.service';

@Component({
  selector: 'app-forgot-password',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  template: `
    <div class="auth-page">
      <div class="auth-container">
        <div class="auth-card">
          <div class="auth-header">
            <h1>Forgot Password</h1>
            <p>We'll send you a reset link</p>
          </div>
          <form (ngSubmit)="onSubmit()" *ngIf="!submitted">
            <div class="form-group">
              <label>Email Address</label>
              <input type="email" [(ngModel)]="email" name="email" required
                placeholder="you@example.com" class="form-control" />
            </div>
            <button type="submit" class="btn-submit" [disabled]="loading">
              {{ loading ? 'Sending...' : 'Send Reset Link' }}
            </button>
          </form>
          <p class="auth-footer"><a routerLink="/auth/login">← Back to login</a></p>
        </div>
      </div>
    </div>
  `,
  styles: [`
    .auth-page {
      min-height: 100vh;
      background: linear-gradient(135deg, #eff6ff 0%, #e0e7ff 100%);
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 20px;
    }
    .auth-container { width: 100%; max-width: 440px; }
    .auth-card {
      background: white;
      border-radius: 20px;
      padding: 40px;
      box-shadow: 0 20px 60px rgba(0,0,0,0.1);
    }
    .auth-header { text-align: center; margin-bottom: 32px; }
    .auth-header h1 { font-size: 1.8rem; font-weight: 700; color: #111827; margin-bottom: 8px; }
    .auth-header p { color: #6b7280; }
    .alert { padding: 12px 16px; border-radius: 8px; margin-bottom: 16px; font-size: 0.9rem; }
    .alert-error { background: #fef2f2; color: #dc2626; border: 1px solid #fecaca; }
    .alert-success { background: #f0fdf4; color: #16a34a; border: 1px solid #bbf7d0; }
    .form-group { margin-bottom: 20px; }
    .form-group label { display: block; margin-bottom: 6px; font-weight: 600; color: #374151; font-size: 0.9rem; }
    .form-control {
      width: 100%;
      padding: 12px 16px;
      border: 2px solid #e5e7eb;
      border-radius: 10px;
      font-size: 1rem;
      outline: none;
      transition: border-color 0.2s;
      box-sizing: border-box;
    }
    .form-control:focus { border-color: #2563EB; }
    .btn-submit {
      width: 100%;
      padding: 14px;
      background: #2563EB;
      color: white;
      border: none;
      border-radius: 10px;
      font-size: 1rem;
      font-weight: 700;
      cursor: pointer;
      transition: background 0.2s;
    }
    .btn-submit:hover:not(:disabled) { background: #1d4ed8; }
    .btn-submit:disabled { opacity: 0.6; cursor: not-allowed; }
    .auth-footer { text-align: center; color: #6b7280; font-size: 0.9rem; margin-top: 20px; }
    .auth-footer a { color: #2563EB; font-weight: 600; text-decoration: none; }
  `]
})
export class ForgotPasswordComponent {
  email = '';
  loading = false;
  submitted = false;

  constructor(private authService: AuthService, private msgService: MessageService) {}

  onSubmit() {
    if (!this.email) { this.msgService.error('Please enter your email'); return; }
    this.loading = true;
    this.authService.forgotPassword(this.email).subscribe({
      next: () => {
        this.loading = false;
        this.submitted = true;
        this.msgService.success('If that email exists, a reset link has been sent.');
      },
      error: (err) => {
        this.loading = false;
        this.msgService.error(err.error?.message || 'Something went wrong');
      }
    });
  }
}
